//! Auto-sync registries for components generated from Godot nodes
//!
//! This module hosts two `inventory`-collected registries populated by the derive macros:
//! - [`AutoSyncBundleRegistry`] — component-creation functions generated by `#[derive(BevyBundle)]`
//!   and `#[godot_components]`, run when a Godot node enters the scene tree.
//! - [`GodotRequiredComponents`] — required-component registrations generated by
//!   `#[godot_components]`, applied to the world at plugin build time.
//!
//! ## Overview
//!
//! These registries eliminate the need to manually register sync plugins in your Bevy app:
//! the macros submit entries via `inventory`, and the scene tree plugin discovers them
//! automatically at startup.

use bevy_app::App;
use bevy_ecs::{entity::Entity, system::Commands, world::World};
use godot::meta::ClassId;
use std::collections::HashMap;
use std::sync::OnceLock;
use tracing::trace;

use crate::interop::{GodotAccess, GodotNodeHandle};

/// Function type for creating bundles from Godot nodes
pub type BundleCreatorFn = fn(&mut Commands, Entity, &mut GodotAccess, GodotNodeHandle) -> bool;

/// Registry entry for auto-sync bundles, constructed only by the derive macros
/// via `inventory::submit!` — `pub` for the macro path, not stable public API.
#[doc(hidden)]
pub struct AutoSyncBundleRegistry {
    /// The bundle struct's name — human-readable, used in trace logs.
    pub godot_class_name: &'static str,
    /// The type's real registered Godot class id (handles `#[class(rename)]`).
    pub godot_class_id_fn: fn() -> ClassId,
    /// Function to create and add the bundle to an entity
    pub create_bundle_fn: BundleCreatorFn,
}

// Collect all auto-sync bundle registrations
crate::inventory::collect!(AutoSyncBundleRegistry);

// Registered creators keyed by Godot class name, built once at plugin build.
static BUNDLE_REGISTRY: OnceLock<HashMap<String, Vec<&'static AutoSyncBundleRegistry>>> =
    OnceLock::new();

/// Initialize the global bundle registry, keyed by Godot class name.
pub fn register_all_autosync_bundles(_app: &mut App) {
    BUNDLE_REGISTRY.get_or_init(|| {
        let mut map: HashMap<String, Vec<&'static AutoSyncBundleRegistry>> = HashMap::new();
        for entry in crate::inventory::iter::<AutoSyncBundleRegistry> {
            map.entry((entry.godot_class_id_fn)().to_string())
                .or_default()
                .push(entry);
        }

        tracing::debug!(
            "Registered {} AutoSyncBundle entries across {} Godot classes",
            map.values().map(Vec::len).sum::<usize>(),
            map.len()
        );
        map
    });
}

/// Add registered bundles for a node, matched by its Godot class hierarchy.
///
/// `class_hierarchy` is the node's class followed by its ancestors (as produced
/// by the scene-tree plugin). A registered type matches iff its class name is in
/// that chain — i.e. the node is-a that type. The matched `create_bundle_fn`
/// still does a `try_get` to retrieve the typed node it builds the bundle from.
pub(crate) fn try_add_bundles_for_node(
    commands: &mut Commands,
    entity: Entity,
    godot: &mut GodotAccess,
    node_handle: GodotNodeHandle,
    class_hierarchy: &[String],
) {
    let Some(registry) = BUNDLE_REGISTRY.get() else {
        return;
    };
    for class_name in class_hierarchy {
        let Some(entries) = registry.get(class_name) else {
            continue;
        };
        for entry in entries {
            if (entry.create_bundle_fn)(commands, entity, godot, node_handle) {
                trace!(
                    "Added bundle for {} to entity {:?}",
                    entry.godot_class_name, entity
                );
            }
        }
    }
}

/// Function type for registering required components generated by `#[godot_components]`
pub type RequiredComponentsRegistrarFn = fn(&mut World);

/// Registry entry for required-components registration using the inventory crate
pub struct GodotRequiredComponents {
    /// The Bevy component the requirements are registered for (for logging)
    pub component_name: &'static str,
    /// Function that registers the component's companions as required components
    pub registrar_fn: RequiredComponentsRegistrarFn,
}

crate::inventory::collect!(GodotRequiredComponents);

/// Run all `#[godot_components]` required-components registrations on this app's world.
///
/// Must run at plugin build time: Bevy requires required-components registration
/// before the target component is ever inserted. Unlike the bundle registry, this
/// is executed (not just collected) per app, since registration is per-World.
pub fn register_all_required_components(app: &mut App) {
    let world = app.world_mut();
    let mut count = 0;
    for entry in crate::inventory::iter::<GodotRequiredComponents> {
        (entry.registrar_fn)(world);
        trace!(
            "Registered required components for {}",
            entry.component_name
        );
        count += 1;
    }
    tracing::debug!("Ran {count} GodotRequiredComponents registrations");
}

#[cfg(test)]
mod tests {
    use super::*;
    use bevy_app::App;
    use bevy_ecs::component::Component;

    #[derive(Component)]
    struct Primary;

    #[derive(Component, Debug, PartialEq)]
    struct Companion(u8);

    crate::inventory::submit! {
        GodotRequiredComponents {
            component_name: "Primary",
            registrar_fn: |world| {
                world.register_required_components_with::<Primary, Companion>(|| Companion(7));
            },
        }
    }

    #[test]
    fn registrar_entries_apply_to_new_world() {
        let mut app = App::new();
        register_all_required_components(&mut app);

        let id = app.world_mut().spawn(Primary).id();
        assert_eq!(app.world().get::<Companion>(id), Some(&Companion(7)));
    }
}
